import React from 'react';
import { View, Text } from 'react-native';
import axios from 'axios';

const API_URL = 'https://api.example.com';

class App extends React.Component {
  constructor(props) {
    super(props);
    this.state = {
      user: null,
      data: null,
      isLoading: false,
    };
  }

  componentDidMount() {
    this.fetchData();
  }

  fetchData = async () => {
    try {
      const response = await axios.get(`${API_URL}/data`);
      this.setState({ data: response.data, isLoading: false });
    } catch (error) {
      console.log(error);
    }
  };

  updateData = async () => {
    try {
      const updatedData = { name: 'New Name', age: 25 };
      await axios.put(`${API_URL}/data`, updatedData);
      this.setState({ data: updatedData, isLoading: false });
    } catch (error) {
      console.log(error);
    }
  };

  render() {
    return (
      <View>
        {this.state.isLoading && <Text>Loading...</Text>}
        {!this.state.isLoading && (
          <Text>{JSON.stringify(this.state.data, null, 2)}</Text>
        )}
        <Button title="Update Data" onPress={this.updateData} />
      </View>
    );
  }
}

export default App;